-export const status = 'pending';
+import { readFile, stat } from 'node:fs/promises';
+
+// ---------------------------------------------------------------------------
+// FileReadCache — avoids resending unchanged file content on repeated reads.
+// ---------------------------------------------------------------------------
+
+interface CacheEntry {
+  content: string;
+  mtimeMs: number;
+  size: number;
+}
+
+export class FileReadCache {
+  private cache = new Map<string, CacheEntry>();
+
+  // -----------------------------------------------------------------------
+  // readFile
+  //
+  // Reads a UTF-8 file.  If the file was already read in this session and
+  // neither its mtime nor its size has changed, the cached content is
+  // returned immediately (fromCache = true) without re-reading from disk.
+  //
+  // Pass { force: true } to bypass the cache and always re-read.
+  // Pass { maxChars } to truncate the returned content (applied to the
+  // cached copy as well so truncation is consistent).
+  // -----------------------------------------------------------------------
+  async readFile(
+    path: string,
+    options?: { force?: boolean; maxChars?: number },
+  ): Promise<{ content: string; fromCache: boolean }> {
+    // --- cache hit path ---------------------------------------------------
+    if (!options?.force) {
+      const cached = this.cache.get(path);
+      if (cached) {
+        try {
+          const st = await stat(path);
+          if (st.mtimeMs === cached.mtimeMs && st.size === cached.size) {
+            const content = this.truncate(cached.content, options?.maxChars);
+            return { content, fromCache: true };
+          }
+        } catch {
+          // File disappeared since last read — evict and fall through.
+          this.cache.delete(path);
+        }
+      }
+    }
+
+    // --- cache miss path --------------------------------------------------
+    const raw = await readFile(path, 'utf-8');
+    const st = await stat(path);
+
+    const content = this.truncate(raw, options?.maxChars);
+    // Always store the *full* content so truncation can vary across calls.
+    this.cache.set(path, { content: raw, mtimeMs: st.mtimeMs, size: st.size });
+
+    return { content, fromCache: false };
+  }
+
+  // -----------------------------------------------------------------------
+  // invalidate
+  //
+  // Evict a single file from the cache, or clear the whole cache when
+  // called with no argument.
+  // -----------------------------------------------------------------------
+  invalidate(path?: string): void {
+    if (path) {
+      this.cache.delete(path);
+    } else {
+      this.cache.clear();
+    }
+  }
+
+  // -----------------------------------------------------------------------
+  // size — number of cached files (useful for inspection / debug).
+  // -----------------------------------------------------------------------
+  get size(): number {
+    return this.cache.size;
+  }
+
+  // -----------------------------------------------------------------------
+  // Private helpers
+  // -----------------------------------------------------------------------
+  private truncate(content: string, maxChars?: number): string {
+    if (maxChars !== undefined && content.length > maxChars) {
+      return content.slice(0, maxChars);
+    }
+    return content;
+  }
+}
+
+// ---------------------------------------------------------------------------
+// Module-level singleton — convenient default for callers that don't need
+// multiple isolated caches.
+// ---------------------------------------------------------------------------
+export const defaultCache = new FileReadCache();
+
+// ---------------------------------------------------------------------------
+// Status export (kept for backward compat).
+// ---------------------------------------------------------------------------
+export const status: string = 'ready';

